mapper.select:
SELECT bpuf.user_id, bpuf.author_time, bpuf.author_user author, bpuf.permission_type, bpd.gb_code, bpd.id data_id, bpd.data_resource_id permission_id, bpuf.`state`, bpgd.group_id, bpm. NAME, bpd.management_id, bpd.org_id, bpd.distribution_type, bpd.based, bpd.data_resource, bpd.data_resource_code, bpd.parent_id, bpuf.option_permission, bpgm.state flag FROM base_permission_user_func bpuf INNER JOIN base_permission_group_data bpgd ON bpuf.permission_id = bpgd.data_id AND bpuf.group_id = bpgd.group_id AND bpuf.`state` = 1 INNER JOIN base_permission_data bpd ON bpd.id = bpgd.data_id AND bpd.`state` = 1 INNER JOIN base_permission_group_management bpgm ON bpgm.group_id = bpuf.group_id AND bpgm.group_id = bpgd.group_id AND bpgm.`state` = 1 INNER JOIN base_permission_management bpm ON bpd.management_id = bpm.id AND bpgm.management_id = bpm.id AND bpm.`state` > 0 WHERE 1 = 1 AND bpuf.permission_type = #{permissionType} AND bpuf.user_id = #{userId} AND bpgd.group_id = #{groupId} and bpd.management_id= #{managementId}
and bpd.distribution_type= #{distributionType}
and bpd.based= #{based} and bpd.data_resource like CONCAT('%',#{dataResource},'%')
group by bpd.data_resource_id

SELECT bpd.gb_code, bpd.id data_id, bpd.data_resource_id permission_id, bpgd.`state`, bpd.org_id, bpgd.group_id, bpm. NAME, bpd.management_id, bpd.distribution_type, bpd.based, bpd.data_resource, bpd.data_resource_code, bpd.parent_id, bpd.option_permission FROM base_permission_group_data bpgd INNER JOIN base_permission_data bpd ON bpd.id = bpgd.data_id AND bpd.`state` = 1 INNER JOIN base_permission_group_management bpgm ON bpgm.group_id = bpgd.group_id AND bpgm.`state` = 0 INNER JOIN base_permission_management bpm ON bpd.management_id = bpm.id AND bpgm.management_id = bpm.id AND bpm.`state` > 0 WHERE 1 = 1 and bpgd.group_id = #{groupId} and bpd.management_id= #{managementId} and bpd.distribution_type= #{distributionType}
and bpd.based= #{based} and bpd.data_resource like CONCAT('%',#{dataResource},'%')
group by bpd.`id`

SELECT '' user_id, bprf.author_time, bprf.author_user author, bprf.permission_type, bpd.gb_code, bpd.id data_id, bpd.data_resource_id permission_id, bprf.`state`, bpgd.group_id, bpm. NAME, bpd.management_id, bpd.org_id, bpd.distribution_type, bpd.based, bpd.data_resource, bpd.data_resource_code, bpd.parent_id, bprf.option_permission FROM base_permission_role_func bprf INNER JOIN base_permission_group_data bpgd ON bprf.permission_id = bpgd.data_id AND bprf.`state` = 1 INNER JOIN base_permission_data bpd ON bpd.id = bpgd.data_id AND bpd.`state` = 1 INNER JOIN base_permission_group_management bpgm ON bpgm.group_id = bprf.group_id AND bpgm.`state` = 1 INNER JOIN base_permission_management bpm ON bpd.management_id = bpm.id AND bpgm.management_id = bpm.id AND bpm.`state` > 0 WHERE 1 = 1 AND bprf.permission_type = #{permissionType} AND bprf.role_id = #{roleId} AND bprf.group_id = #{groupId} and bpd.management_id= #{managementId}
and bpd.distribution_type= #{distributionType}
and bpd.based= #{based} and bpd.data_resource like CONCAT('%',#{dataResource},'%')
group by bpd.`id`

SELECT tmp.permission_id org_id, tmp.group_id FROM ( SELECT 'user' type, bpuf.permission_id, bpuf.group_id, ( CASE WHEN bpgp.param_value = '[{"name":"是","select":"0"},{"name":"否","select":"1"}]' THEN 'role' WHEN bpgp.param_value = '[{"name":"是","select":"1"},{"name":"否","select":"0"}]' THEN 'user' ELSE 'role' END ) groupType FROM base_permission_user_func bpuf INNER JOIN base_permission_group_param bpgp ON bpuf.group_id = bpgp.group_id AND bpuf.permission_type = 'org' WHERE bpuf.user_id in
#{userId}
UNION ALL SELECT 'role' type, bprf.permission_id, bprf.group_id, ( CASE WHEN bpgp.param_value = '[{"name":"是","select":"0"},{"name":"否","select":"1"}]' THEN 'role' WHEN bpgp.param_value = '[{"name":"是","select":"1"},{"name":"否","select":"0"}]' THEN 'user' ELSE 'role' END ) groupType FROM base_permission_user_role bpur INNER JOIN base_permission_role_func bprf ON bpur.role_id = bprf.role_id AND bpur.group_id = bprf.group_id AND bprf.permission_type = 'org' INNER JOIN base_permission_group_param bpgp ON bprf.group_id = bpgp.group_id AND bpur.user_id in
#{userId}
) tmp WHERE tmp.type = tmp.groupType

SELECT bpd.gb_code, bpd.id data_id, bpd.data_resource_id permission_id, bpd.org_id, bpgd.group_id, bpm. NAME, bpd.management_id, bpd.distribution_type, bpd.based, bpd.data_resource, bpd.data_resource_code, bpd.parent_id, bpgm.state flag FROM base_permission_data bpd INNER JOIN base_permission_group_data bpgd ON bpd.id = bpgd.data_id AND bpd.`state` = 1 AND bpgd.`state` = 1 INNER JOIN base_permission_management bpm ON bpd.management_id = bpm.id INNER JOIN base_permission_group_management bpgm ON bpgm.management_id = bpm.id AND bpm.`state` > 0 WHERE 1 = 1 AND bpgm.group_id = #{groupId} and bpd.management_id= #{managementId} and bpd.distribution_type= #{distributionType}
and bpd.based= #{based} and bpd.data_resource like CONCAT('%',#{dataResource},'%')
group by bpd.`id`

SELECT bpd.gb_code, bpd.id data_id, bpd.data_resource_id permission_id, bpd.org_id, bpgd.group_id, bpm. NAME, bpd.management_id, bpd.distribution_type, bpd.based, bpd.data_resource, bpd.data_resource_code, bpd.parent_id, bpgm.state flag FROM base_permission_group_data bpgd INNER JOIN base_permission_data bpd ON bpd.id = bpgd.data_id AND bpd.`state` = 1 AND bpgd.`state` = 1 INNER JOIN base_permission_group_management bpgm ON bpgm.group_id = bpgd.group_id INNER JOIN base_permission_management bpm ON bpd.management_id = bpm.id AND bpgm.management_id = bpm.id AND bpm.`state` > 0 WHERE 1 = 1 AND bpgd.group_id = #{groupId} and bpd.management_id= #{managementId} and bpd.distribution_type= #{distributionType}
and bpd.based= #{based} and bpd.data_resource like CONCAT('%',#{dataResource},'%')
group by bpd.`id`

