(#{userId},'func',#{item},#{groupId},#{authorUser},#{authorTime},#{state},#{createdBy},#{createdName},#{createdDate})
;

delete from base_permission_user_func where user_id=#{userId} and group_id=#{groupId} and permission_type='org' and state=1; insert into base_permission_user_func(user_id,permission_type,permission_id,group_id,author_user,author_time,state,created_by,created_name,created_date) values
